// Limpa entidades num raio ao redor do jogador. O mod só remove UM prefab
// por comando, então percorremos a lista e emitimos um remove_near_player por
// prefab. Ajuste TARGETS e RADIUS à vontade.
function run(context) {
  const userid = context.trigger && context.trigger.userid;
  if (!userid) return { skipped: 'no userid' };

  const RADIUS = 30;   // alcance da limpeza (tiles)
  const LIMIT = 999;   // por prefab

  // Bosses + mobs hostis comuns. Não inclui estruturas, baús, jogadores.
  const TARGETS = [
    'deerclops', 'bearger', 'moose', 'dragonfly', 'antlion', 'minotaur',
    'klaus', 'klaus_sack', 'toadstool', 'beequeen', 'crabking', 'malbatross',
    'stalker', 'warg', 'spiderqueen',
    'spider', 'spider_warrior', 'spider_hider', 'spider_spitter', 'spider_dropper',
    'hound', 'firehound', 'icehound', 'killerbee', 'mosquito', 'frog',
    'tentacle', 'merm', 'tallbird', 'krampus', 'spat', 'worm', 'batilisk',
    'crawlinghorror', 'terrorbeak', 'nightmarebeak'
  ];

  for (const prefab of TARGETS) {
    context.sendCommand('remove_near_player', { userid: userid, prefab: prefab, radius: RADIUS, limit: LIMIT });
  }
  return { cleared: TARGETS.length, radius: RADIUS };
}
